from dataclasses import dataclass, field
from enum import Enum

class ElementType(Enum):
    EXTERNAL_ENTITY = "external_entity"
    PROCESS         = "process"
    DATA_STORE      = "data_store"

class TrustLevel(Enum):
    UNTRUSTED  = 0
    USER       = 1
    OPERATOR   = 2
    DEVELOPER  = 3

@dataclass
class DFDElement:
    id: str
    name: str
    element_type: ElementType
    trust_level: TrustLevel
    description: str

@dataclass
class DataFlow:
    source_id: str
    target_id: str
    label: str
    crosses_trust_boundary: bool
    data_classification: str       # e.g. "user_instruction", "tool_output", "pii"

@dataclass
class AgentDFD:
    elements: list[DFDElement] = field(default_factory=list)
    flows: list[DataFlow] = field(default_factory=list)

    def trust_boundary_flows(self) -> list[DataFlow]:
        """Return all flows that cross a trust boundary — these are the threat vectors."""
        return [f for f in self.flows if f.crosses_trust_boundary]

    def external_inputs(self) -> list[DataFlow]:
        """Return all flows originating from external entities (untrusted sources)."""
        external_ids = {e.id for e in self.elements if e.trust_level == TrustLevel.UNTRUSTED}
        return [f for f in self.flows if f.source_id in external_ids]

@dataclass
class DREADScore:
    threat_id: str
    damage: int        # 1-10: how bad if exploited?
    reproducibility: int  # 1-10: how easy to reproduce?
    exploitability: int   # 1-10: how much skill required?
    affected_users: int   # 1-10: how many users impacted?
    discoverability: int  # 1-10: how easy to find?

    @property
    def score(self) -> float:
        return (
            self.damage + self.reproducibility + self.exploitability
            + self.affected_users + self.discoverability
        ) / 5.0

    @property
    def rating(self) -> str:
        s = self.score
        if s >= 8: return "critical"
        if s >= 6: return "high"
        if s >= 4: return "medium"
        return "low"

class ThreatRegister:
    def __init__(self):
        self._threats: list[Threat] = []
        self._scores:  dict[str, DREADScore] = {}

    def add_threat(self, t: Threat, score: DREADScore | None = None) -> None:
        self._threats.append(t)
        if score:
            self._scores[t.id] = score

    def prioritised(self) -> list[Threat]:
        def sort_key(t: Threat) -> int:
            s = self._scores.get(t.id)
            return int(s.score * 10) if s else 0
        return sorted(self._threats, key=sort_key, reverse=True)

    def open_critical(self) -> list[Threat]:
        return [
            t for t in self._threats
            if t.mitigation_status == "open" and t.risk_rating == "critical"
        ]

    def mitigated_percentage(self) -> float:
        if not self._threats:
            return 100.0
        done = sum(1 for t in self._threats if t.mitigation_status == "mitigated")
        return done / len(self._threats) * 100
